#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,K,L; scanf("%d %d %d",&N,&K,&L);
        int *S = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d",&S[i]);
        int maxOther = -2147483648;
        for(int i=0;i<N-1;i++) if(S[i]>maxOther) maxOther=S[i];
        int friendSpeed = S[N-1];
        int ans = 0;
        if(friendSpeed>maxOther) ans=1;
        else if(K>0){
            long long finalSpeed = (long long)friendSpeed + (long long)(L-1)*K;
            if(finalSpeed>maxOther) ans=1;
        }
        // K<=0 and not already winning -> ans stays 0
        printf(ans?"Yes\n":"No\n");
        free(S);
    }
    return 0;
}

