public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int K = Integer.parseInt(st.nextToken());
            int L = Integer.parseInt(st.nextToken());
            int[] S = new int[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) {
                S[i] = Integer.parseInt(st.nextToken());
            }
            int maxOther = Integer.MIN_VALUE;
            for (int i = 0; i < N - 1; i++) if (S[i] > maxOther) maxOther = S[i];
            int friendSpeed = S[N - 1];
            boolean ok = false;
            if (friendSpeed > maxOther) ok = true;
            else if (K > 0) {
                long long finalSpeed = (long long)friendSpeed + (long long)(L - 1) * K;
                if (finalSpeed > maxOther) ok = true;
            }
            sb.append(ok ? "Yes" : "No").append('\n');
        }
        System.out.print(sb.toString());
