#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it)); L = int(next(it))
        speeds = [int(next(it)) for _ in range(N)]
        max_other = max(speeds[:-1]) if N>1 else -10**9
        friend = speeds[-1]
        ok = False
        if friend > max_other:
            ok = True
        elif K > 0:
            final = friend + (L-1)*K
            if final > max_other:
                ok = True
        # K <= 0 and not already winning -> cannot help
        out.append('Yes' if ok else 'No')
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

